  @fn resetToSnapshot()  @ 518-521
      -- Revert the edited composite to the open()/switch snapshot, then reswing.
  @fn buildDescriptor()  @ 525-544
  @fn nearestRpb(v)  @ 591-598
      -- Rows/qn is a fixed ladder of valid divisions; the stepper walks adjacent rungs
